80	export async function initDatabase() {
81	  try {
82	    // Initialize sql.js
83	    const wasmBinary = fs.readFileSync(
84	      path.join(__dirname, '../node_modules/sql.js/dist/sql-wasm.wasm')
85	    );
86	    SQL = await initSqlJs({ wasmBinary });
87	
88	    // Set database path in user data directory
89	    const userDataPath = app.getPath('userData');
90	    dbPath = path.join(userDataPath, 'clockhelp.db');
91	
92	    console.log('Database path:', dbPath);
