94	    // Load existing database or create new one
95	    const isSQLiteHeader = (buf) =>
96	      buf.length >= 16 &&
97	      buf[0] === 0x53 && buf[1] === 0x51 && buf[2] === 0x4c && buf[3] === 0x69;
98	
99	    const tryLoad = (filePath) => {
100	      if (!fs.existsSync(filePath)) return null;
101	      const buf = fs.readFileSync(filePath);
102	      if (!isSQLiteHeader(buf)) {
103	        console.warn(`Skipping invalid database file: ${filePath}`);
104	        return null;
105	      }
106	      return buf;
107	    };
108	
109	    const candidates = [
110	      dbPath,
111	      `${dbPath}.backup.1`,
112	      `${dbPath}.backup.2`,
113	      `${dbPath}.backup.3`,
114	      dbPath + '.bak',
115	    ];
116	    const buffer = candidates.reduce((found, p) => found || tryLoad(p), null);
117	
118	    if (buffer) {
119	      db = new SQL.Database(buffer);
120	      console.log('Loaded existing database');
121	    } else {
122	      db = new SQL.Database();
123	      console.log('Created new database (existing files were invalid)');
124	    }
