148	function migrateTimeEntriesTaskId() {
149	  try {
150	    // Check if task_id column is NOT NULL by trying to get table info
151	    const tableInfo = db.exec('PRAGMA table_info(time_entries)');
152	    if (tableInfo.length > 0) {
153	      const columns = tableInfo[0].columns;
154	      const notNullIdx = columns.indexOf('notnull');
155	      const nameIdx = columns.indexOf('name');
156	      const taskIdRow = tableInfo[0].values.find(row => row[nameIdx] === 'task_id');
157	      if (taskIdRow && taskIdRow[notNullIdx] === 1) {
158	        // Need to recreate table to allow NULL task_id
159	        // Run each statement separately for reliability
160	        db.run('DROP TABLE IF EXISTS time_entries_new');
161	        db.run(`CREATE TABLE time_entries_new (
162	            id INTEGER PRIMARY KEY AUTOINCREMENT,
163	            task_id INTEGER,
164	            start_time TEXT NOT NULL,
165	            end_time TEXT,
166	            duration_seconds INTEGER,
167	            is_lunch_break INTEGER DEFAULT 0,
168	            notes TEXT,
169	            created_at TEXT DEFAULT CURRENT_TIMESTAMP,
170	            FOREIGN KEY (task_id) REFERENCES tasks(id)
171	          )`);
172	        db.run('INSERT INTO time_entries_new SELECT * FROM time_entries');
173	        db.run('DROP TABLE time_entries');
174	        db.run('ALTER TABLE time_entries_new RENAME TO time_entries');
175	        db.run('CREATE INDEX IF NOT EXISTS idx_time_entries_task_id ON time_entries(task_id)');
176	        db.run('CREATE INDEX IF NOT EXISTS idx_time_entries_start_time ON time_entries(start_time)');
