215	export function saveDatabase() {
216	  if (!db || !dbPath) {
217	    console.error('Cannot save database: not initialized');
218	    return;
219	  }
220	
221	  try {
222	    const data = db.export();
223	    const buffer = Buffer.from(data);
224	
225	    if (buffer.length < 512) {
226	      console.error('Refusing to save: exported database is suspiciously small', buffer.length, 'bytes');
227	      return;
228	    }
229	    const isSQLiteHeader = (buf) =>
230	      buf[0] === 0x53 && buf[1] === 0x51 && buf[2] === 0x4c && buf[3] === 0x69;
231	    if (!isSQLiteHeader(buffer)) {
232	      console.error('Refusing to save: exported data does not have a valid SQLite header');
233	      return;
234	    }
235	
236	    // Write to temp file first — if power cuts here, the current .db is untouched
237	    const tempPath = dbPath + '.tmp';
238	    fs.writeFileSync(tempPath, buffer);
239	
240	    // Verify the written file is good before rotating backups
241	    const written = fs.readFileSync(tempPath);
242	    if (!isSQLiteHeader(written)) {
243	      fs.unlinkSync(tempPath);
244	      console.error('Refusing to rotate backups: temp file failed verification');
245	      return;
246	    }
247	
248	    // Rotate rolling backups: backup.2 → backup.3, backup.1 → backup.2, .db → backup.1
249	    for (let i = ROLLING_BACKUPS - 1; i >= 1; i--) {
250	      const older = `${dbPath}.backup.${i + 1}`;
251	      const newer = `${dbPath}.backup.${i}`;
252	      if (fs.existsSync(newer)) {
253	        if (fs.existsSync(older)) fs.unlinkSync(older);
254	        fs.renameSync(newer, older);
255	      }
256	    }
257	    if (fs.existsSync(dbPath)) {
258	      fs.renameSync(dbPath, `${dbPath}.backup.1`);
259	    }
260	
261	    fs.renameSync(tempPath, dbPath);
262	    console.log('Database saved successfully');
263	  } catch (error) {
264	    console.error('Failed to save database:', error);
265	  }
266	}
